                    DateTimeOffset.Now.AddDays(-1),
                    DateTimeOffset.Now.AddYears(5));

                return new X509Certificate2(
                    certificate.Export(X509ContentType.Pfx, "password"),
                    "password",
                    X509KeyStorageFlags.MachineKeySet | X509KeyStorageFlags.PersistKeySet);
